int loadData(char *filename,std::vector<Record> &records,std::vector<LatLong> &locations){
    FILE   *flist,*fp;
	int    i=0;
	char dbname[64];
	int recNum=0;



    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error opening filelist\n");
        exit(0);
    }

	while(!feof(flist)) {





		if(fscanf(flist, "%s\n", dbname) != 1) {
            if (feof(flist)) break;
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        fp = fopen(dbname, "r");
        if(!fp) {
            printf("error opening a db\n");
            exit(1);
        }

        while(!feof(fp)){
            Record record;
            LatLong latLong;
            // Initialize recString to ensure safety
            memset(record.recString, 0, REC_LENGTH);

            if (fgets(record.recString, 49, fp) == NULL) break;

            // consume newline if present or handle end of file
            int c = fgetc(fp); 
            if (c == EOF && feof(fp)) break;


            char substr[6];

            for(i=0;i<5;i++) {
                int idx = i + 28;
                if (idx < 49 && record.recString[idx] != '\0')
                    substr[i] = record.recString[idx];
                else
                    substr[i] = '0'; // fallback
            }
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for(i=0;i<5;i++) {
                int idx = i + 33;
                if (idx < 49 && record.recString[idx] != '\0')
                    substr[i] = record.recString[idx];
                else
                    substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);

    return recNum;
}

void findLowest(std::vector<Record> &records,float *distances,int numRecords,int topN){
  int i,j;
  float val;
  int minLoc;
  Record tempRec;
  float tempDist;

  for(i=0;i<topN;i++) {
    minLoc = i;
    for(j=i;j<numRecords;j++) {
      val = distances[j];
      if (val < distances[minLoc]) minLoc = j;
    }

    tempRec = records[i];
    records[i] = records[minLoc];
    records[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;


    records[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d){
    int i;
    if (argc < 2) return 1; 
    strncpy(filename,argv[1],100);
    char flag;

    for(i=1;i<argc;i++) {
      if (argv[i][0]=='-') {
        flag = argv[i][1];
          switch (flag) {
            case 'r': 
              if (i+1 < argc) {
                  i++;
                  *r = atoi(argv[i]);
              }
              break;
            case 'l': 
              if (i+1 < argc) {
                  if (argv[i][2]=='a') {
                    *lat = atof(argv[i+1]);
                  }
                  else {
                    *lng = atof(argv[i+1]);
                  }
                  i++;
              }
              break;
            case 'h': 
              return 1;
            case 'q': 
              *q = 1;
              break;
            case 't': 
              *t = 1;
              break;
            case 'p': 
              if (i+1 < argc) {
                  i++;
                  *p = atoi(argv[i]);
              }
              break;
            case 'd': 
              if (i+1 < argc) {
                  i++;
                  *d = atoi(argv[i]);
              }
              break;
        }
      }
    }
    if ((*d >= 0 && *p<0) || (*p>=0 && *d<0)) 
      return 1;
    return 0;
}

